





























import Vue from 'vue'
import {Component, Prop} from "vue-property-decorator";
import dayjs from 'dayjs'

@Component
export default class WishListItem extends Vue {
  @Prop({type: Object, required: true}) item!: TWishListItem

  show = false

  showImages() {
    if (this.item.status === 'done') {
      this.show = !this.show
    }
  }

  getDate(rawDate: string) {
    return dayjs(rawDate).format('YYYY-MM-DD');
  }
}
